package com.samlsp.config;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.io.ResourceLoader;

import java.io.InputStream;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.X509Certificate;

@Configuration
public class KeyStoreConfig {

    @Autowired
    private SAMLProperties samlProperties;

    @Autowired
    private ResourceLoader resourceLoader;

    @Bean
    public KeyStore samlKeyStore() throws Exception {
        KeyStore keyStore = KeyStore.getInstance("JKS");
        try (InputStream is = resourceLoader.getResource(samlProperties.getKeystorePath()).getInputStream()) {
            keyStore.load(is, samlProperties.getKeystorePassword().toCharArray());
        }
        return keyStore;
    }

    @Bean
    public X509Certificate spCertificate(KeyStore samlKeyStore) throws Exception {
        return (X509Certificate) samlKeyStore.getCertificate(samlProperties.getKeyAlias());
    }

    @Bean
    public PrivateKey spPrivateKey(KeyStore samlKeyStore) throws Exception {
        return (PrivateKey) samlKeyStore.getKey(
                samlProperties.getKeyAlias(),
                samlProperties.getKeyPassword().toCharArray()
        );
    }

    @Bean
    public X509Certificate idpCertificate() throws Exception {
        try (InputStream is = resourceLoader.getResource(samlProperties.getIdp().getCertificatePath()).getInputStream()) {
            java.security.cert.CertificateFactory cf = java.security.cert.CertificateFactory.getInstance("X.509");
            return (X509Certificate) cf.generateCertificate(is);
        }
    }
}

