package com.samlsp.config;

import com.samlsp.security.SAMLAuthenticationFilter;
import com.samlsp.security.SAMLAuthenticationProvider;
import com.samlsp.security.SAMLEntryPoint;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilder;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Autowired
    private SAMLAuthenticationProvider samlAuthenticationProvider;

    @Autowired
    private SAMLEntryPoint samlEntryPoint;

    @Bean
    public AuthenticationManager authenticationManager(HttpSecurity http) throws Exception {
        AuthenticationManagerBuilder authBuilder = http.getSharedObject(AuthenticationManagerBuilder.class);
        authBuilder.authenticationProvider(samlAuthenticationProvider);
        return authBuilder.build();
    }

    @Bean
    public SAMLAuthenticationFilter samlAuthenticationFilter(AuthenticationManager authenticationManager) {
        SAMLAuthenticationFilter filter = new SAMLAuthenticationFilter("/saml/acs");
        filter.setAuthenticationManager(authenticationManager);
        return filter;
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http,
                                                    SAMLAuthenticationFilter samlAuthenticationFilter) throws Exception {
        http
            .csrf(csrf -> csrf
                .ignoringRequestMatchers("/saml/**")
            )
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/saml/**", "/saml/metadata", "/login", "/error", "/health").permitAll()
                .anyRequest().authenticated()
            )
            .exceptionHandling(ex -> ex
                .authenticationEntryPoint(samlEntryPoint)
            )
            .addFilterBefore(samlAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
            .logout(logout -> logout
                .logoutUrl("/saml/slo/init")
                .logoutSuccessUrl("/login?logout")
            );

        return http.build();
    }
}

